    results.hero = {
      bgType: hasImage ? (bg.includes('url') ? 'image' : 'gradient') : 'none',
      bgValue: bg ? bg.substring(0,120) : 'none',
      textColor: getComputedStyle(hero).color,
      height: hero.offsetHeight + 'px',
      padding: getComputedStyle(hero).padding,
    };
  }

  // 2. Typography check
  const headings = document.querySelectorAll('h1, h2, h3');
  const fontLoads = [];
  headings.forEach(h => {
    const style = getComputedStyle(h);
    fontLoads.push({tag: h.tagName, text: h.textContent.substring(0,30), font: style.fontFamily, weight: style.fontWeight, size: style.fontSize, color: style.color});
  });
  results.typography = fontLoads.slice(0,8);

  // 3. Portfolio grid
  const portfolioImgs = document.querySelectorAll('[class*="portfolio"] img, [class*="gallery"] img, section:nth-of-type(3) img, section:nth-of-type(4) img');
  const imgInfo = [];
  portfolioImgs.forEach(img => {
    imgInfo.push({
      src: img.src ? img.src.substring(0,80) : 'no-src',
      loaded: img.complete && img.naturalWidth > 0,
      dims: img.naturalWidth + 'x' + img.naturalHeight,
      display: getComputedStyle(img).display,
      parentTag: img.parentElement?.tagName || '?',
    });
  });
  results.portfolioImages = imgInfo.slice(0,15);

  // 4. Process section
  const processSteps = document.querySelectorAll('[class*="process"] .step, [class*="process"] > div > div');
  const steps = [];
  processSteps.forEach(s => {
    const h = s.querySelector('h3');
    const p = s.querySelector('p');
    steps.push({heading: h?.textContent?.substring(0,30) || '', para: p?.textContent?.substring(0,50) || '', visible: s.offsetHeight > 0});
  });
  results.processSteps = steps;

  // 5. CTA banner
  const cta = document.querySelector('[class*="cta"], [class*="banner"]');
  if (cta) {
    results.ctaBanner = {
      bg: getComputedStyle(cta).background?.substring(0,60),
      height: cta.offsetHeight + 'px',
      hasLink: !!cta.querySelector('a'),
      hasButton: !!cta.querySelector('button'),
    };
  }

  // 6. Footer
  const footer = document.querySelector('footer');
  if (footer) {
    results.footer = {
      height: footer.offsetHeight + 'px',
      links: footer.querySelectorAll('a').length,
      hasWhatsapp: footer.textContent.includes('WhatsApp') || footer.textContent.includes('wa.me'),
      bg: getComputedStyle(footer).background?.substring(0,60),
    };
  }

  // 7. Overall spacing
  const body = document.body;
  results.pageWidth = body.scrollWidth + 'px';
  results.hasHorizontalScroll = body.scrollWidth > window.innerWidth;

  // 8. Console errors
  results.jsErrors = window.__hermes_errors || [];

  // 9. Performance
  results.performance = {
    domNodes: document.querySelectorAll('*').length,
    imagesTotal: document.images.length,
    imagesLoaded: Array.from(document.images).filter(i => i.complete).length,
  };

  // 10. Responsive - check if mobile breakpoints exist
  const styleSheets = document.styleSheets;
  let mediaQueries = 0;
  try {
    for (const ss of styleSheets) {
      try {
        for (const rule of ss.cssRules || []) {
          if (rule instanceof CSSMediaRule && rule.conditionText.includes('max-width')) {
            mediaQueries++;
          }
        }
      } catch(e) { /* cross-origin */ }
    }
  } catch(e) {}
  results.responsive = { mediaQueriesFound: mediaQueries };

  // 11. Color contrast check
  const allText = document.querySelectorAll('p, h1, h2, h3, h4, a, span, li');
  let lowContrast = 0;
  allText.forEach(el => {
    const color = getComputedStyle(el).color;
    const bg = getComputedStyle(el).backgroundColor;
    if (color && bg && bg !== 'rgba(0, 0, 0, 0)') lowContrast++;
  });
  results.colorContrast = { elementsChecked: allText.length };

  return JSON.stringify(results, null, 2);
})()"}

