  // Extract all inline styles and class-based styling from the rendered page
  const styles = [];
  const sheets = document.styleSheets;
  for (let i = 0; i < sheets.length; i++) {
    try {
      const rules = sheets[i].cssRules;
      if (!rules) continue;
      for (let j = 0; j < rules.length; j++) {
        const r = rules[j];
        if (r.selectorText && (r.selectorText.includes('hero') || r.selectorText.includes('section') || r.selectorText.includes('header') || r.selectorText.includes('footer') || r.selectorText.includes('process') || r.selectorText.includes('portfolio') || r.selectorText.includes('gallery') || r.selectorText.includes('cta'))) {
          styles.push({selector: r.selectorText, css: r.cssText?.substring(0,150)});
        }
      }
    } catch(e) {}
  }
  return JSON.stringify({styleCount: styles.length, topStyles: styles.slice(0,20)});
})()"}

