  // Extract ALL CSS custom properties and key design tokens
  const root = document.documentElement;
  const cs = getComputedStyle(root);
  const allTokens = {};
  for (let i = 0; i < cs.length; i++) {
    const prop = cs[i];
    if (prop.startsWith('--')) {
      allTokens[prop] = cs.getPropertyValue(prop).trim();
    }
  }
  // Check heading font rendering
  const h1 = document.querySelector('h1');
  const h1style = h1 ? {font: getComputedStyle(h1).fontFamily, size: getComputedStyle(h1).fontSize, weight: getComputedStyle(h1).fontWeight, letterSpacing: getComputedStyle(h1).letterSpacing, lineHeight: getComputedStyle(h1).lineHeight} : 'no h1';

  // Check image loading status
  const imgs = document.querySelectorAll('img');
  const imgStatus = Array.from(imgs).slice(0,10).map(i => ({
    src: i.getAttribute('src')?.substring(0,60),
